input.command:
bash -c "echo 'import json, sys
from collections import defaultdict

with open(\"/tmp/all_orders.json\") as f:
    orders = json.load(f)

groups = defaultdict(list)
for o in orders:
    key = (o[\"user_id\"], o[\"total_cents\"])
    groups[key].append(o)

print(\"=== DUPLICATE GROUPS (same user_id + total_cents, 2+ orders) ===\")
for key, group in sorted(groups.items()):
    if len(group) >= 2:
        print(f\"User: {key[0]}, Amount: {key[1]} cents, Count: {len(group)}\")
        for o in sorted(group, key=lambda x: x[\"created_at\"]):
            print(f\"  {o['id']} | {o['status']} | {o['created_at']} | products: {o['product_ids']}\")
        print()

print(\"=== NEAR-DUPLICATE CHECK (same user + amount, within 60s) ===\")
from datetime import datetime, timedelta
for key, group in sorted(groups.items()):
    if len(group) >= 2:
        sorted_group = sorted(group, key=lambda x: x[\"created_at\"])
        for i in range(len(sorted_group)):
            for j in range(i+1, len(sorted_group)):
                t1 = datetime.fromisoformat(sorted_group[i][\"created_at\"].replace(\"Z\",\"\"))
                t2 = datetime.fromisoformat(sorted_group[j][\"created_at\"].replace(\"Z\",\"\"))
                diff = (t2 - t1).total_seconds()
                if diff <= 60:
                    print(f\"  {sorted_group[i]['id']} and {sorted_group[j]['id']}: {diff}s apart\")

print(f\"Total orders: {len(orders)}\")
statuses = defaultdict(int)
for o in orders:
    statuses[o[\"status\"]] += 1
print(f\"Status breakdown: {dict(statuses)}\")
' > /tmp/analyze.py"

